{"file_path":"ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/SpacingAroundColonAnnotationRuleTest.kt","content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class SpacingAroundColonAnnotationRuleTest {
    private val spacingAroundColonRuleAssertThat = assertThatRule { SpacingAroundColonRule() }

    @Test
    fun `Given an annotation with space before colon`() {
        val code =
            """
            @file :JvmName("Foo")
            """.trimIndent()
        val formattedCode =
            """
            @file:JvmName("Foo")
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolation(1, 7, "Unexpected spacing before \":\"")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given an annotation with space after colon`() {
        val code =
            """
            @file: JvmName("Foo")
            """.trimIndent()
        val formattedCode =
            """
            @file:JvmName("Foo")
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolation(1, 7, "Unexpected spacing after \":\"")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given an annotation with space before and after colon`() {
        val code =
            """
            @file : JvmName("Foo")
            """.trimIndent()
        val formattedCode =
            """
            @file:JvmName("Foo")
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(1, 7, "Unexpected spacing before \":\""),
                LintViolation(1, 7, "Unexpected spacing after \":\"")
            )
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given an annotation entry with space before and after colon`() {
        val code =
            """
            @set : [Inject VisibleForTesting]
            """.trimIndent()
        val formattedCode =
            """
            @set:[Inject VisibleForTesting]
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(1, 6, "Unexpected spacing before \":\""),
                LintViolation(1, 6, "Unexpected spacing after \":\"")
            )
            .isFormattedAs(formattedCode)
    }
}
"}

